public static ETGAgreementConfirmControllerExtension construct()
{
    return new ETGAgreementConfirmControllerExtension();
}

public static void main(Args _args)
{
    SrsReportRunController formLetterController = ETGAgreementConfirmControllerExtension::construct();
    ETGAgreementConfirmControllerExtension controller = formLetterController;
    if (!CurrentCompanyIsSpanishCompany())
    {
        controller.parmReportName(ssrsReportStr(ETGAgreementConfirmation, ETGPurchContractReport));
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETGAgreementConfirmation, Report));
    }
    controller.parmArgs(_args);
    controller.startOperation();
}
